// ============================================================
// Fetch Central Grants
// Queries the central_grants catalog directly instead of scraping
// external sources. The daily ingest workflow keeps the catalog
// fresh; this node just reads from it and hands results to the
// AI filter downstream.
// ============================================================

const webhookData = $('search for proposal with query').first().json.body;
const searchId = webhookData.search_id;
const orgId = webhookData.org_id;
const searchQuery = (webhookData.searchQuery || '').trim();

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';

const supaReadHeaders = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
};
const supaWriteHeaders = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal',
};

async function writeStatus(message) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: supabaseUrl + '/search_results',
      headers: supaWriteHeaders,
      body: JSON.stringify({
        search_id: searchId,
        org_id: orgId,
        source_group: '__status__:checking',
        grant_data: { status: 'checking', stage_message: message },
        is_complete: false,
      }),
    });
  } catch(e) {}
}

if (!searchId || !orgId) return [];

await writeStatus.call(this, 'Loading grants from catalog...');

// PostgREST ilike needs asterisks as wildcards. Escape commas, parens,
// and quotes that would break the `or=(...)` filter syntax.
function safeIlike(s) {
  return String(s || '').replace(/[\\(),"*]/g, ' ').trim();
}
const q = safeIlike(searchQuery);

// Build the PostgREST URL. If the user gave us a query, fuzzy-match
// against title/description/funder_name. Otherwise return the most
// recently-seen rows so the AI has something to rank.
const selectCols = 'id,title,funder_name,organization,description,source,source_id,source_url,deadline,amount,eligibility,categories,metadata';
let url;
if (q) {
  const orClause = [
    'title.ilike.*' + encodeURIComponent(q) + '*',
    'description.ilike.*' + encodeURIComponent(q) + '*',
    'funder_name.ilike.*' + encodeURIComponent(q) + '*',
  ].join(',');
  url = supabaseUrl + '/central_grants?select=' + selectCols + '&or=(' + orClause + ')&limit=500&order=last_seen_at.desc';
} else {
  url = supabaseUrl + '/central_grants?select=' + selectCols + '&limit=500&order=last_seen_at.desc';
}

let rows = [];
try {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: url,
    headers: supaReadHeaders,
  });
  if (Array.isArray(res)) rows = res;
} catch(e) {}

// Drop expired grants. Null deadline means rolling / open-ended — keep.
const todayIso = new Date().toISOString().slice(0, 10);
const live = rows.filter(r => !r.deadline || r.deadline >= todayIso);

// Emit one n8n item per grant. Alias funder_name → agency and
// source_id → oppNum so the downstream AI-filter node (which reads
// those field names) doesn't need to change.
return live.map(r => ({
  json: {
    id: r.id,
    oppNum: r.source_id || r.id,
    title: r.title || '',
    description: r.description || '',
    agency: r.funder_name || '',
    funder_name: r.funder_name || '',
    organization: r.organization || '',
    source: r.source || '',
    source_id: r.source_id || null,
    source_url: r.source_url || null,
    deadline: r.deadline || null,
    amount: r.amount || null,
    eligibility: r.eligibility || null,
    categories: r.categories || null,
    metadata: r.metadata || null,
  },
}));

// ============================================================
// AI Filter & Save Grants
// Takes grants fetched from central_grants, runs them through
// OpenAI in batches of 30 for relevance filtering, and writes
// matches to search_results progressively so the UI can stream
// them in.
// ============================================================

const AI_BATCH = 30;
const items = $input.all();
const webhookData = $('search for proposal with query').first().json.body;
const searchId = webhookData.search_id;
const orgId = webhookData.org_id;
const searchQuery = webhookData.searchQuery;
const orgType = webhookData.orgType || 'Any';
const profitStatus = webhookData.profitStatus || 'Any';
const industry = webhookData.industry || 'Any';
const fundingCategory = webhookData.fundingCategory || 'Any';

const openAiKey = 'REPLACE_ME';

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';
const supaHeaders = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal',
};

async function writeSearchResult(data) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/search_results',
    headers: supaHeaders,
    body: JSON.stringify(data),
  });
}

const allGrants = items.map(i => i.json).filter(g => (g.title || '').trim());
const totalGrants = allGrants.length;

// --- STEP 1: If nothing came back from the catalog, mark done and exit.
if (totalGrants === 0) {
  try {
    await writeSearchResult.call(this, {
      search_id: searchId,
      org_id: orgId,
      source_group: '__done__',
      grant_data: [],
      is_complete: true,
    });
  } catch(e) {}
  return [{ json: { success: true, message: 'No grants found in catalog', totalMatched: 0 } }];
}

// --- STEP 2: Initial status row so the UI shows activity.
try {
  await writeSearchResult.call(this, {
    search_id: searchId,
    org_id: orgId,
    source_group: '__status__:filtering',
    grant_data: { status: 'filtering', stage_message: 'Found ' + totalGrants + ' candidate grants. Matching to your search...' },
    is_complete: false,
  });
} catch(e) {}

// --- STEP 3: Batch through OpenAI for relevance filtering.
const totalBatches = Math.ceil(totalGrants / AI_BATCH);
let totalMatched = 0;
const allMatched = [];

const systemPrompt = `You are a grant relevance filter. You receive a search query, optional filters, and a list of grants. Your job is to decide which
grants are genuinely relevant to the user's search.

FILTERING RULES:
1. Analyze the search query to understand the specific domain, topic, and intent.
2. Keep a grant ONLY if its Title or Description directly relates to the query's core topic.
3. Discard a grant if the connection to the search query requires more than one logical hop or is only tangential.
4. When in doubt, DISCARD. Users prefer fewer, highly relevant results over many loosely related ones.

ADDITIONAL FILTERS (apply only if the value is provided and not "Any" or empty):
- Organization Type: Only keep grants whose eligible applicants include this org type.
- Nonprofit/For-Profit Status: If "Nonprofit", discard grants only for for-profits. If "For-Profit", discard grants only for nonprofits. If "Either" or
empty, skip.
- Industry/Sector: Only keep grants relevant to this sector. Use semantic matching.
- Funding Category: "Federal Grant" = only federal. "Foundation / Private Grant" = only philanthropic/foundation. If empty, skip.
- Geographic Focus: If provided, only keep grants whose eligibility includes this geographic area.

Return ONLY a valid JSON object with two properties:
- "ids": array of IDs of grants that pass ALL filters
- "no_results": boolean, true if no grants matched

Example with matches: {"ids": ["361204", "358858", "352411"], "no_results": false}
Example with no matches: {"ids": [], "no_results": true}

Do NOT return markdown or explanation. Just the JSON object.`;

for (let b = 0; b < totalBatches; b++) {
  const start = b * AI_BATCH;
  const batch = allGrants.slice(start, start + AI_BATCH);
  const grantsSoFar = start + batch.length;

  try {
    await writeSearchResult.call(this, {
      search_id: searchId,
      org_id: orgId,
      source_group: '__status__:filtering',
      grant_data: { status: 'filtering', stage_message: 'Matching ' + grantsSoFar + ' of ' + totalGrants + ' grants to your search...' },
      is_complete: false,
    });
  } catch(e) {}

  const grantsForAI = batch.map(g => ({
    id: String(g.id || g.oppNum || ''),
    title: g.title || '',
    description: (g.description || '').substring(0, 500),
    agency: g.funder_name || g.agency || '',
  }));

  const userPrompt = `Search Query: ${searchQuery}

Filters:
- Organization Type: ${orgType}
- Nonprofit/For-Profit: ${profitStatus}
- Industry/Sector: ${industry}
- Funding Category: ${fundingCategory}

Grants to evaluate:
${JSON.stringify(grantsForAI, null, 2)}`;

  let keepIds = [];
  try {
    const aiResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/chat/completions',
      headers: {
        'Authorization': 'Bearer ' + openAiKey,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        model: 'gpt-4.1-mini',
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt },
        ],
        temperature: 0,
      }),
    });
    const aiText = aiResponse.choices?.[0]?.message?.content || '{}';
    const cleaned = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const parsed = JSON.parse(cleaned);
    keepIds = Array.isArray(parsed) ? parsed : (parsed.ids || []);
    keepIds = keepIds.map(String);
  } catch(e) {
    keepIds = [];
  }

  const matched = batch.filter(g => keepIds.includes(String(g.id || g.oppNum || '')));

  if (matched.length > 0) {
    totalMatched += matched.length;
    // Shape each matched row to match the DiscoveredGrant the UI expects.
    const grantData = matched.map(g => ({
      title: g.title,
      funder_name: g.funder_name || g.agency || 'Unknown',
      organization: g.organization || '',
      description: g.description || '',
      amount: g.amount || null,
      deadline: g.deadline || null,
      stage: 'discovery',
      source: g.source || '',
      source_id: g.source_id || null,
      source_url: g.source_url || null,
      eligibility: g.eligibility || null,
      categories: g.categories || null,
      metadata: g.metadata || null,
    }));
    allMatched.push(...grantData);

    try {
      await writeSearchResult.call(this, {
        search_id: searchId,
        org_id: orgId,
        source_group: 'ai_filtered_' + b,
        grant_data: grantData,
        is_complete: false,
      });
    } catch(e) {}
  }
}

// --- STEP 4: Mark search complete.
try {
  await writeSearchResult.call(this, {
    search_id: searchId,
    org_id: orgId,
    source_group: '__done__',
    grant_data: [],
    is_complete: true,
  });
} catch(e) {}

return allMatched.map(g => ({ json: g }));
